signature.raw:
VkResult vkGetPhysicalDeviceVideoFormatPropertiesKHR(
 VkPhysicalDevice physicalDevice,
 const VkPhysicalDeviceVideoFormatInfoKHR* pVideoFormatInfo,
 uint32_t* pVideoFormatPropertyCount,
 VkVideoFormatPropertiesKHR* pVideoFormatProperties);

details.example:
VkPhysicalDevice physicalDevice = VK_NULL_HANDLE;
VkPhysicalDeviceVideoFormatInfoKHR videoFormatInfo = {};
videoFormatInfo.sType = VK_STRUCTURE_TYPE_PHYSICAL_DEVICE_VIDEO_FORMAT_INFO_KHR;
uint32_t videoFormatPropertyCount = 0;
VkVideoFormatPropertiesKHR videoFormatProperties = {};
videoFormatProperties.sType = VK_STRUCTURE_TYPE_VIDEO_FORMAT_PROPERTIES_KHR;

VkResult result = vkGetPhysicalDeviceVideoFormatPropertiesKHR(
 physicalDevice,
 &videoFormatInfo,
 &videoFormatPropertyCount,
 &videoFormatProperties
);

